class Solution:
    def checkArithmeticSubarrays(self, nums, l, r):
        result = []
        for lo, hi in zip(l, r):
            sub = sorted(nums[lo:hi + 1])
            is_arith = True
            if len(sub) >= 2:
                diff = sub[1] - sub[0]
                for i in range(2, len(sub)):
                    if sub[i] - sub[i - 1] != diff:
                        is_arith = False
                        break
            result.append(is_arith)
        return result

