var checkArithmeticSubarrays = function(nums, l, r) {
    const result = [];
    for (let q = 0; q < l.length; q++) {
        const sub = nums.slice(l[q], r[q] + 1).slice().sort((a, b) => a - b);
        let isArith = true;
        if (sub.length >= 2) {
            const diff = sub[1] - sub[0];
            for (let i = 2; i < sub.length; i++) {
                if (sub[i] - sub[i - 1] !== diff) {
                    isArith = false;
                    break;
                }
            }
        }
        result.push(isArith);
    }
    return result;
};
